export default class Lightbox extends Component {
  render() {
    return (
      <div>
        
        <>
          <div><img src="./images/image-product-1." alt="" /></div>
          <div><img src="./images/image-product-2" alt="" /></div>
          <div><img src="./images/image-product-3" alt="" /></div>
          <div><img src="./images/image-product-4" alt="" /></div>
        </>
        <p>this is p</p>
      </div>
    )
  }
}
